window.__dh_data["da"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "Dhammapada",
  "chaps": "Kapitler",
  "fontsize": "Skriftstørrelse",
  "chap1": "Dobbel-Strofer",
  "1": "Alle Foreteelser er betinget af Tanken, er behersket af Tanken, udgøres af Tanken; den der taler eller handler med uren Tanke, ham følger Ulykken i Hælene ligesom Hjulet Trækdyrets Fod.",
  "2": "Alle Foreteelser er betinget af Tanken, er behersket af Tanken, udgøres af Tanken; den der taler eller handler med ren Tanke, ham følger Lykken i Hælene, uadskillelig som hans Skygge.",
  "3": "'Han har smædet mig','Han har slaaet mig','Han har besejret mig','Han har røvet, hvad der var mit': hos dem, der gør sig saadanne Tanker om andre, svinder Hadet aldrig.",
  "4": "'Han har smædet mig','Han har slaaet mig','Han har besejret mig','Han har røvet, hvad der var mit': hos dem, der ikke tænker saadan om andre, svinder Hadet.",
  "5": "Thi aldrig bringes her i Verden Had til Ophør ved Had; ved Mildhed svinder Had; det er en evig Lov.",
  "6": "Og Mængden forstaar ikke, at vi her maa betvinge os; har man indset det, saa bliver Skærmydslerne til intet.",
  "7": "Den der blot lever for at søge Nydelser; den som ikke har Hold paa sine Sanser og er umaadeholden overfor Mad, ørkesløs og svag, ham kaster Mâra visselig til Jorden, som Stormen et skrøbeligt Træ.",
  "8": "Den der lever uden at søge Nydelser; den som har Hold paa sine Sanser og er maadeholden overfor Mad, tillidsfuld og kraftig, ham kan Mâra ikke kaste til Jorden, saalidt som Stormen en Granitklippe.",
  "9": "Den der uden at have renset sig for Synd, uden Maadehold og Sandhed vil iføre sig den gule Munkekutte, han er den ikke værdig.",
  "10": "Men den der har udspyet Synden, og som vogter nøje paa det gode i sig; den som har vundet Maadehold og Sandhed, han fortjener visselig Munkekutten.",
  "11": "De der anser det uvæsentlige for væsentligt og det væsentlige for uvæsentligt, de naar aldrig til det væsentlige; men deres Stræben er rettet mod forkert Maal.",
  "12": "Men de der har lært at anse det væsentlige for væsentligt og det uvæsentlige for uvæsentligt, de naar til det væsentlige; og deres Stræben har det rette Maal.",
  "13": "Ligesom Regnen fra øverst til nederst trænger igennem et Hus med daarligt Tag, saaledes gennemtrænger Begær den uskolede Tanke helt.",
  "14": "Ligesom Regnen ikke formaar at trænge igennem et Hus med godt Tag, saaledes gennemtrænger Begær ikke den skolede Tanke.",
  "15": "Den der øver ondt, han sørger her, og han sørger hisset; han sørger begge Steder; han sørger, og han ræddes, naar han ser sine Handlingers Besmittelse.",
  "16": "Den der øver godt, han glæder sig her, og han glæder sig hisset; han glæder sig begge Steder; han glæder sig, og han fryder sig, naar han ser sine Handlingers Renhed.",
  "17": "Den der øver ondt, han pines her, og han pines hisset; han pines begge Steder; han pines ved Tanken om at have handlet slet, og han pines ydermere, naar hans Skæbne fører ham til Helvede.",
  "18": "Den der øver godt, han fryder sig her, og han fryder sig hisset; han fryder sig begge Steder; han fryder sig ved Tanken om at have handlet godt, og han fryder sig ydermere, naar hans Skæbne fører ham til Himlen.",
  "19": "Den der taler mange velføjede Ord, men er slap og ikke handler derefter, han er kun som en Hyrde, der tæller andres Køer; han hører ikke til de rette Buddha-lærlinge.",
  "20": "Den der kun taler faa velføjede Ord, men følger Lovens Bud, aflægger Begær, Had og Forblindelse, har den rette Erkendelse og en frigjort Tanke, intet attraar her eller hisset, han hører til de rette Buddha-lærlinge.",
  "chap2": "Anspændelse",
  "21": "Anspændelse er Udødelighedens Sfære, Slaphed Dødens; de agtpaagivne dør ikke, de slappe er allerede som døde.",
  "22": "Naar de i Anspændelse kyndige har indset dette til Bunds, saa glæder de sig ved Anspændelsen og finder deres Lykke blandt de ædle.",
  "23": "De der formaar at fæstne Tanken; de udholdende, der stadig er i Besiddelse af urokkelig Styrke, saadanne vise Mænd vinder Nirvâna, den højeste Sikkerhed.",
  "24": "Den der er beslutsom og har Hold paa sin Tanke; den hvis Handlinger er rene og velovervejede; den der har Herredømme over sine Sanser og lever efter Loven og under Anspændelse, hans Ry vokser.",
  "25": "Ved Beslutsomhed, Anspændelse, Selvbeherskelse og Fasthed kan den vise Mand skabe sig en Ø, som Vandmasserne aldrig overskyller.",
  "26": "Taaber og dumme Mennesker hylder Slaphed; den vise Mand vogter paa Anspændelse som paa sin bedste Skat.",
  "27": "Man skal ikke hylde Slaphed og ikke knytte sig til Elskov og Lyst; den der er anspændt og behersker sin Tanke, vinder stor Lykke.",
  "28": "Naar den kyndige ved Anspændelse har forjaget Slapheden, saa bestiger han Erkendelsens Tinde og beskuer selv sorgløs de sorgfyldte Skabninger, ligesom den vise, der staar paa et Bjerg, beskuer Taaberne nede paa Jorden.",
  "29": "Anspændt blandt de slappe, lysvaagen blandt de sovende lader den vise Mand de andre bag sig ligesom en rask Hest den affældige.",
  "30": "Ved Anspændelse blev Indra Gudernes Herre; Anspændelse berømmes og Slaphed dadles til enhver Tid.",
  "31": "Den Tiggermunk, der glæder sig ved Anspændelse og betragter Slaphed med Rædsel, han vandrer afsted, idet han som en Ild brænder tynde og svære Baand sønder.",
  "32": "Den Tiggermunk, der glæder sig ved Anspændelse og betragter Slaphed med Rædsel, han er ude af Stand til at falde tilbage, han er Nirvâna nær.",
  "chap3": "Tanken",
  "33": "Ustadig og urolig er Tanken, vanskelig at vogte og holde i Tømme; den retter den vise ligesom Pilesmeden sin Pil.",
  "34": "Ligesom en Fisk, der er taget op af sit Hjem i Vandet og kastet paa Jorden, saaledes spræller vor Tanke for at undfly Mâras Rige.",
  "35": "Godt er det at mestre Tanken, der er vanskelig at faa Hold paa, er flygtig og strejfer om efter eget Forgodtbefindende; den mestrede Tanke bringer Lykke.",
  "36": "Den vise skal vogte sin Tanke, der er svær at iagttage, svær at faa fat paa, og som strejfer om efter eget Forgodtbefindende; den vel vogtede Tanke bringer Lykke.",
  "37": "De der faar Hold paa Tanken, der vandrer vidt omkring, og som strejfer om alene uden Legemet eller hviler i Hjærtet, de vil blive løst fra Mâras Lænker.",
  "38": "Den Mands Erkendelse vil aldrig blive fuldkommen, hvis Tanke er ustadig, hvis Sindsro vakler, og som ikke kender den rette Lære.",
  "39": "Den aarvaagne behøver ikke at frygte; han hvis Tanke er ubesmittet, hvis Sind ikke rokkes, og som er hinsides godt og ondt.",
  "40": "Betragtende Legemet som et skrøbeligt Kar og befæstende Tanken som en Borg skal man bekæmpe Mâra med Erkendelsens Vaaben, vogte ham vel, naar han er besejret, og aldrig slaa sig til Ro.",
  "41": "Ak, om kort Tid vil mit Legeme ligge paa Jorden, uden Bevidsthed, slængt hen som en unyttig Træklods.",
  "42": "Hvad ondt det ene Menneske i sit Had tilføjer det andet, eller den ene Fjende den anden, noget langt værre end det vil en vildledet Tanke tilføje et Menneske.",
  "43": "Saa meget formaar ikke en Moder, en Fader eller andre Slægtninge, noget langt bedre end det vil en retledet Tanke bringe et Menneske.",
  "chap4": "Blomster",
  "44": "Hvem er det, der vil sejre over Jorden her og over Yamas Verden og Guderne hisset? Hvem vil sanke den sande Læres skønne Ord, som den kyndige sanker Blomster?",
  "45": "Den der giver sig i Lære hos Buddha, vil sejre over Jorden her og over Yamas Verden og Guderne hisset; han vil sanke den sande Læres skønne Ord, som den kyndige sanker Blomster.",
  "46": "Den der indser, at vort Legeme er uvirkeligt som Skum, og forstaar, at det er forgængeligt som en Luftspejling, han bryder Mâras Blomsterpile og undgaar Synet af Dødskongen.",
  "47": "Døden fører med sig en Mand, der sanker Blomster, og hvis Tanke er andetsteds, ligesom Floden den sovende Landsby.",
  "48": "Døden bemægtiger sig en Mand, der sanker Blomster, og hvis Tanke er andetsteds, før han har faaet sine Ønsker tilfredsstillet.",
  "49": "Som en Bi fjerner sig med Blomstens Saft uden at skade dens Farve eller Duft, paa samme Maade skal en Vismand optræde i Landsbyen.",
  "50": "Ikke med andres Fejl, ikke med andres Handlinger eller Forsømmelser skal man holde Øje, men med sine egne Handlinger og Forsømmelser.",
  "51": "Som en skøn Blomst, der vel har straalende Farver, men ingen Duft, saaledes er velklingende Ord uden Frugt hos den, der ikke handler derefter.",
  "52": "Som en skøn Blomst, der baade har straalende Farver og Duft, saaledes bærer velklingende Ord Frugt hos den, der handler derefter.",
  "53": "Ligesom man af en Bunke Blomster kan forme mange Slags Blomsterkranse, saaledes kan Mennesket, naar det er kommet til Verden, udrette mangfoldigt godt.",
  "54": "Blomsternes Duft breder sig ikke imod Vinden, hverken fra Sandeltræ, Tagara eller Jasmin; men gode Menneskers Duft breder sig imod Vinden; et godt Menneske gennemtrænger alle Verdenshjørner.",
  "55": "Sandeltræ, Tagara, Lotus og Jasmin: al den Duft, de frembringer, er intet mod Duften af det gode.",
  "56": "Tarvelig er Duften fra Tagara og Sandeltræ; men Duften af gode Mennesker trænger op til Guderne som den ypperste.",
  "57": "Til gode Mennesker, der lever under Anspændelse, og som er frelste ved den rette Erkendelse, til dem finder Mâra ikke Vej.",
  "58": "Ligesom en Lotusblomst, lifligt duftende og skøn, kan vokse frem paa en Affaldsdynge, kastet ud paa Landevejen,",
  "59": "saaledes straaler ved sin Erkendelse den, der lytter til Buddha, blandt de blinde Hverdagsmennesker, Menneskehedens Affald.",
  "chap5": "Taaben",
  "60": "Lang er Natten for den, der ligger vaagen; lang er Vejen for den trætte; lang er Tilværelsen for de Taaber, der ikke kender den sande Lære.",
  "61": "Hvis man paa sin Vandring ikke træffer nogen, der er bedre end en selv eller ens Ligemand, saa skal man trøstigt vandre alene; Daarer er intet Følgeskab.",
  "62": "'Jeg har Sønner, jeg har Rigdom' saadanne Bekymringer gør Taaben sig; han er ikke engang Herre over sig selv, hvor meget mindre over Sønner og Rigdom.",
  "63": "Den Taabe, der indser sin Daarskab, han er for saa vidt vis; men den Taabe, der anser sig for vis, han kan i Sandhed kaldes en Taabe.",
  "64": "Selv om en Taabe hele sit Liv igennem omgaas en vis Mand, fornemmer han dog ikke den sande Lære, ligesaa lidt som Skeen Suppens Smag.",
  "65": "Hvis en klog Mand blot et Øjeblik omgaas en vis, saa fornemmer han straks den sande Lære, ligesom Tungen Suppens Smag.",
  "66": "Taaberne optræde i deres Daarskab som deres egne Fjender, idet de udfører onde Gerninger, som bærer bitter Frugt.",
  "67": "Den Gerning er ikke vel gjort, hvis Udførelse man angrer, og hvis Frugter man nyder grædende og med Taarer i Øjnene.",
  "68": "Men den Gerning er vel gjort, hvis Udførelse man ikke angrer, og hvis Frugter man nyder glad og tilfreds.",
  "69": "Saalænge den onde Gerning ikke har baaret Frugt, betragter Taaben den som Honning; men naar den bærer Frugt, saa føler han Smerten.",
  "70": "Selv om en Taabe Maaned efter Maaned spiser sin Mad paa Spidsen af et Kusa-Græs, saa er han dog ikke en Sekstendedel saa meget værd som de, der forstaar den sande Læres Værd.",
  "71": "Thi en ond Gerning undergaar ikke straks Ændring, saadan som Mælk; men brændende følger den Taaben, som Ild dækket af Asken.",
  "72": "Kun til Unytte skaffer Daaren sig Indsigt; den sprænger hans Hoved og ødelægger Stakkelens gode Del.",
  "73": "Han vil stræbe efter slette Menneskers Agtelse, efter Forrang blandt Tiggermunkene, efter Herredømmet i Klostrene, efter Ære i andre Familier:",
  "74": "'Baade Lægfolk og Munke skal regne med mine Handlinger; mig skal de underkaste sig i alt, hvad der skal gøres eller ikke gøres!' saadan er Taabens Ønske; og hans Begær og Indbildskhed vokser.",
  "75": "En Lære fører til Rigdom, en anden til Nirvâna; naar Tiggermunken, Buddhas Lærling, har indset det, saa vil han ikke glæde sig over Æresbevisninger, men hellige sig Ensomhed.",
  "chap6": "Den Vise Mand",
  "76": "Naar man ser en klog Mand, der viser en, hvad der er Synd, og dadler, hvad der fortjener det, saa skal man følge en saadan vis Mand ligesom en, der angiver, hvor Skatte er skjult; følger man en saadan Mand, gaar det en bedre, ikke værre.",
  "77": "Lad ham dadle, lad ham belære, lad ham forhindre, hvad der ikke er hæderligt; gode Mennesker vil holde af ham, onde vil hade ham.",
  "78": "Man skal ikke have onde Mennesker til Venner, og ikke ringe Mennesker; tag gode Mennesker og de bedste Mennesker til Venner!",
  "79": "Den der glæder sig ved den rette Lære, lever lykkeligt med afklaret Sind; den vise Mand fryder sig altid ved den rette Lære, som den forkyndes af de ædle.",
  "80": "Kanalbyggerne leder Vandet; Pilesmedene retter Pilene; Tømrerne retter Træet; den, der er vis, tvinger sig selv.",
  "81": "Som en massiv Klippe ikke bevæges af Vinden, saaledes lader vise Mennesker sig ikke paavirke af Dadel eller Ros.",
  "82": "Som en dyb, klar og stille Sø, saaledes afklares vise Mennesker, naar de hører Loven.",
  "83": "Gode Mennesker optræder som gode Mennesker under alle Forhold; de hyler ikke op i lystent Begær; de der er kloge, viser sig ikke opstemt eller nedslaaet, eftersom de er ramt af Lykke eller Ulykke.",
  "84": "Hverken for sin egen eller for andres Skyld skal man ønske sig Sønner, Rigdom eller Magt; god, forstandig og retsindig er den Mand, som ikke søger sin egen Lykke ved uretmæssige Midler.",
  "85": "Kun faa er blandt Menneskene de, der naar Kysten paa den anden Side; de øvrige Skabninger løber op og ned langs Kysten her.",
  "86": "Men de Mennesker, som følger den rette Lære, der er forkyndt paa rette Vis, de naar den anden Side; Dødens Omraade er vanskeligt at komme igennem.",
  "87": "Den, der er vis, skal forlade Mørkets Lære og lægge sig efter Lysets Lære; naar han har ombyttet sit Hjem med Hjemløshed, skal han søge sin Glæde i glædeløs Ensomhed;",
  "88": "uden Begær, uden Besiddelse skal den vise Mand rense sig for Tankens Besmittelser.",
  "89": "De hvis Tanke er vel skolet i den fulde Erkendelses forskellige Led; de som uden at knytte sig til nogen Ting finder Glæde i Forsagelse; de som straaler, befriet for alle onde Indflydelser, de har naaet Nirvâna allerede her paa Jorden.",
  "chap7": "De Hellige",
  "90": "Der findes ingen Lidelse hos den, der har naaet Vejens Ende; der er uden Bekymring; der er frigjort til alle Sider, og som har friet sig for alle Baand.",
  "91": "De anspænder sig og holder Tanken fast; de finder ingen Glæde i Hjemmet; de forlader Hus og Hjem ligesom Vandregæs, der har forladt deres Dam.",
  "92": "De som ikke har samlet Rigdom, men kun lever af den paabudte Kost; de som kun tænker paa den betingelsesløse, endelige Frelse, deres Vej er lige saa svær at følge som Fuglenes i Luften.",
  "93": "Den der er helt fri for onde Indflydelser; den som er uafhængig af, hvad han spiser, og som kun tænker paa den betingelsesløse, endelige Frelse, hans Vej er lige saa svær at følge som Fuglenes i Luften.",
  "94": "Selv Guderne misunder den, hvis Sanser er tæmmet, ligesom Heste, Kusken har Herredømmet over; den som er uden Hovmod og fri for onde Indflydelser.",
  "95": "En saadan from Mand er taalsom som Jorden eller som en Tærskel, han er som en klar Sø; for ham er Tilværelsen til Ende.",
  "96": "Naar en saadan Mand har fundet Hvile og er frelst ved ret Erkendelse, saa falder hans Tanke til Ro og hans Tale og Gerninger.",
  "97": "Den Mand, der ikke er lettroende, som erkender det uskabte og har brudt alle Baand; den som har vist alle Fristelser fra sig og kastet alt Haab tilside, han er i Sandhed den bedste Mand.",
  "98": "Det være sig i Landsby eller Skov, paa Havet eller Landjorden, overalt, hvor de hellige dvæler, gør de Stedet skønt.",
  "99": "Skove er skønne; der hvor andre Mennesker ikke finder Glæde, der glæder de sig, som intet attraar, thi de søger ikke Lyst.",
  "chap8": "Tusinder",
  "100": "Om det saa var tusind Sætninger, føjet sammen af Ord uden Indhold, saa er ét Ord med Indhold bedre, hvis det bringer Fred, naar vi hører det.",
  "101": "Om det saa var tusind Strofer, føjet sammen af Ord uden Indhold, saa er én Strofes Ord bedre, hvis den bringer Fred, naar vi hører den.",
  "102": "Om man end fremsagde hundrede Strofer, føjet sammen af Ord uden Indhold, saa er dog ét af den sande Læres Ord bedre, hvis det bringer Fred, naar man hører det.",
  "103": "Om man end besejrede tusinde og atter tusinde Mænd i Slaget, saa er dog den, der besejrer sig selv alene, den største Sejrherre.",
  "104": "Det er bedre at besejre sig selv end alle andre Mennesker; naar et Menneske har Herredømme over sig selv og stadig lever i Selvbeherskelse,",
  "105": "saa formaar ingen Gud, ingen Aand, ikke Mâra og Brahman at gøre denne Sejr til et Nederlag for et saadant Menneske.",
  "106": "Hvis en Mand hundrede Aar igennem hver Maaned ofrer tusinde Ofre, eller hvis han blot et Øjeblik ærer en, der har skolet sit Jeg, saa er denne Hyldest bedre end hundrede Aars Ofre.",
  "107": "Hvis en Mand hundrede Aar igennem vedligeholder Offerilden i Skoven, eller hvis han blot et Øjeblik ærer en, der har skolet sit Jeg, saa er denne Hyldest bedre end hundrede Aars Ofre.",
  "108": "Hvad end en Mand for at indlægge sig Fortjeneste ofrer et Aar igennem af Ofre eller Offergaver her i Verden, alt det er ikke en Fjerdedel værd, bedre er Hyldest overfor dem, der gaar den rette Vej.",
  "109": "Den der altid er ærbødig og ærer de gamle, hos ham er der fire Ting, der udvikles: Livskraft, Skønhed, Lykke og Styrke.",
  "110": "Om man end levede hundrede Aar, men ond og uden Hold paa sine Tanker, saa er det bedre at leve en enkelt Dag som en from Mand med Tanken fæstnet.",
  "111": "Om man end levede hundrede Aar, men uforstandig og uden Hold paa sine Tanker, saa er det bedre at leve en enkelt Dag som en forstandig Mand med Tanken fæstnet.",
  "112": "Om man end levede hundrede Aar, men ørkesløs og slap, saa er det bedre at leve en enkelt Dag som en kraftig og beslutsom Mand.",
  "113": "Om man end levede hundrede Aar, men uden at se Tingene opstaa og forgaa, saa er det bedre at leve en enkelt Dag og se Tingene opstaa og forgaa.",
  "114": "Om man end levede hundrede Aar, men uden at se Udødelighedens Sfære, saa er det bedre at leve en enkelt Dag og se Udødelighedens Sfære.",
  "115": "Om man end levede hundrede Aar, men uden at fatte den ypperste Lære, saa er det bedre at leve en enkelt Dag og fatte den ypperste Lære.",
  "chap9": "Det Onde",
  "116": "Man skal ile mod det gode og holde Tanken borte fra det onde; thi den der uvilligt gør det gode, hans Tanke glæder sig ved det onde.",
  "117": "Hvis et Menneske handler ondt, saa skal han ikke gøre det atter og atter, og han skal ikke føle nogen Glæde ved det, thi Ophobning af ondt er Lidelse.",
  "118": "Hvis et Menneske handler godt, saa skal han gøre det atter og atter, og han skal ikke føle Glæde ved det, thi Ophobning af godt er Lykke.",
  "119": "Det onde Menneske ser ogsaa gode Dage, saalænge den onde Gerning ikke har baaret Frugt; naar den onde Gerning har baaret Frugt, saa ser han onde Dage.",
  "120": "Det gode Menneske ser ogsaa onde Dage, saalænge den gode Gerning ikke har baaret Frugt; naar den gode Gerning har baaret Frugt, saa ser han gode Dage.",
  "121": "Man skal ikke undervurdere det onde i den Tanke: det vil aldrig komme mig nær; en Vandkrukke fyldes ved Vanddraabernes Falden, og Taaben fyldes med ondt, selv om han kun samler det lidt efter lidt.",
  "122": "Man skal ikke undervurdere det gode i den Tanke: det vil aldrig komme mig nær; en Vandkrukke fyldes ved Vanddraabernes Falden, og den vise fyldes med godt, selv om han kun samler det lidt efter lidt.",
  "123": "Som en Købmand med mange Skatte og faa Ledsagere holder sig fra en farlig Vej; som den livslystne holder sig fra Gift, saadan skal man holde sig fra onde Gerninger.",
  "124": "Den der ikke har Saar paa Haanden, han kan gribe om Gift med Haanden; naar han intet Saar har, skader den ham ikke; ved den, som intet ondt gør, hæfter intet ondt.",
  "125": "Naar en Taabe søger at skade en uskyldig, ren og syndefri Mand, saa falder det onde tilbage paa ham selv, ligesom fint Støv, man kaster imod Vinden.",
  "126": "Nogle fødes paany; de der handler ondt, gaar til Helvede; de gode kommer i Himlen; de der er uden alle onde Indflydelser, naar Nirvâna.",
  "127": "Ikke i Himmelrummet, ikke i Havets Midte, ikke hvis man flygter ind i Bjergenes Hule, intetsteds i Verden findes en Plet, hvor man kan fri sig fra sine onde Gerninger.",
  "128": "Ikke i Himmelrummet, ikke i Havets Midte, ikke hvis man flygter ind i Bjergenes Hule, intetsteds i Verden findes en Plet, hvor Døden ikke kan naa en.",
  "chap10": "Vold",
  "129": "Alle skælver for Vold, alle frygter Døden; idet man sætter sig i andres Sted, skal man ikke dræbe og ikke lade dræbe.",
  "130": "Alle skælver for Vold, alle elsker Livet; idet man sætter sig i andres Sted, skal man ikke dræbe og ikke lade dræbe.",
  "131": "Den der for sin egen Lykkes Skyld øver Vold mod andre Væsener, der søger Lykke, han finder ingen Lykke efter Døden.",
  "132": "Den der ikke for sin egen Lykkes Skyld ved Vold skader andre Væsener, der søger Lykke, han finder Lykke efter Døden.",
  "133": "Tal ikke haardt til nogen; de, der tiltales, vil svare paa samme Maade; voldsomme Ord bringer Sorg; voldelig Gengældelse vil ramme Dig.",
  "134": "Hvis Du lader være med at komme i Bevægelse, naar Du rammes, som et Bækken, man slaar paa, saa har Du naaet Nirvâna, saa er Du ikke udsat for nogen Vold mere.",
  "135": "Ligesom en Kohyrde med sin Stav driver Køerne paa Græs, saaledes driver Alderdom og Død de levendes Levetid afsted.",
  "136": "En Taabe er sig ikke bevidst, naar han forøver sine onde Handlinger; men den Daare vil pines af sine Gerninger, som brændtes han af Ild.",
  "137": "Den der farer voldelig frem mod værgeløse og uskyldige, han vil hurtigt komme i en af følgende ti Tilstande:",
  "138": "Voldsom legemlig Smerte, Svækkelse, Brud paa Lemmer, alvorlig Sygdom eller Sindsforvirring vil ramme ham;",
  "139": "Overlast fra Fyrstens Side, en frygtelig falsk Anklage, Tab af Slægtninge, eller Svind af hans Skatte;",
  "140": "eller Ildebrand vil brænde hans Huse; og naar hans Legeme er opløst, gaar den Taabe til Helvede.",
  "141": "Det Menneske, som ikke har overvundet sit Begær, han renses ikke ved at gaa nøgen, ved at bære flettet Haar, ved Smuds, ved Faste, ved at sove paa den bare Jord, ved at smøre sig ind i Støv eller ved at sidde ubevægelig.",
  "142": "Den der, om han og er velklædt, øver Retfærd og er i Besiddelse af Sindsro, Selvbeherskelse, tæmmede Sanser og Kyskhed, og som ikke øver Vold mod noget Væsen, han er en Brahman, han er en Buddha-lærling, han er en Tiggermunk.",
  "143": "Hvilken Mand findes der her i Verden saa behersket af Skamfølelse, at han kan ringeagte Dadel, som en ædel Hest Pisken? I skal være ihærdige og ivrige som en ædel Hest, der har følt Pisken.",
  "144": "Ved Tro, ved Godhed, ved Styrke, ved Tankens Fasthed og ved Betragtning af den rette Lære vil I, fuldkomne i Viden og Vandel og med Hold paa Eders Tanker, kunne komme ud over den store Lidelse.",
  "145": "Kanalbyggerne leder Vandet; Pilesmedene retter Pilen; Tømrerne retter Træet; de fromme tvinger sig selv.",
  "chap11": "Alderdom",
  "146": "Hvor kan man le, og hvor kan man glæde sig, naar Ilden flammer uophørligt? I der er omgivet af Mørke, vil I ikke søge Lyset?",
  "147": "Se paa dette opstadsede Billede fuldt af Saar, oppustet, sygt, fuldt af Begær og uden Fasthed, uden Bestand.",
  "148": "Dette Legeme er udslidt, et Sygdommens Arnested, skrøbeligt, en Bunke Raaddenskab, der opløser sig, thi Livet munder ud i Døden.",
  "149": "Disse blegnede Knogler, kastet hen som Græskar ved Høsttid, hvem kan glæde sig, naar han har set dem?",
  "150": "Af Knogler bygges en By, Kød og Blod smøres ovenpaa; der bor Alderdom og Død, Hovmod og Hykleri.",
  "151": "Selv Fyrstens pragtfulde Vogne ældes, og ogsaa vort Legeme er underkastet Alderen; men det gode hos gode Mennesker ældes aldrig, det melder gode Mennesker os, alle som en.",
  "152": "Det Menneske, der kun har lært lidt, bliver gammel paa Oksers Vis; hans Krop vokser, men hans Forstand vokser ikke.",
  "153": "Mange Fødslers Kredsløb har jeg gennemløbet, uden Held søgende Husets Bygmester; og at fødes atter og atter er Lidelse.",
  "154": "Men nu har jeg set Dig, Bygmester; Du bygger ikke Hus mere; alle dine Tagsparrer er brudte, og Husets Gavl er styrtet sammen; Tanken er uden Spirer til nyt Liv og har naaet til Drifternes Ophør.",
  "155": "Den der ikke i sin Ungdom har gennemgaaet sin Læretid og samlet Skatte, han omkommer ligesom den gamle Trane i Søen uden Fisk.",
  "156": "Den der ikke i sin Ungdom har gennemgaaet sin Læretid og samlet Skatte, han ligger som en knækket Bue og jamrer over sin Fortid.",
  "chap12": "Jeget",
  "157": "Har man sit Jeg kært, saa skal man vogte det omhyggeligt; en af de tre Nattevagter skal den vise Mand tilbringe vaagen.",
  "158": "Først skal man befæste sit eget Jeg i hvad der er Ret; saa kan man belære andre; og den vise Mand vil ikke føle Fortrydelse.",
  "159": "Sit eget Jeg skal man forme saadan, som man lærer andre at være; naar man behersker sig selv rigtigt, kan man beherske andre; thi Jeget er svært at faa Herredømme over.",
  "160": "Jeget er sin egen Herre, hvem ellers skulde være dets Herre? Naar man først har Herredømme over sig selv, saa finder man en Herre, som han vanskelig findes.",
  "161": "Den onde Gerning, som man selv har begaaet, som er født af ens Jeg og har sin Oprindelse i ens Jeg, den knuser Taaben, ligesom Diamanten den haardeste Ædelsten.",
  "162": "Den hvis Karakter er ødelagt til Bunds, han bringer sig selv i en Forfatning, som blot hans Fjende kan ønske det, ligesom en Slyngplante det Træ, den omslynger.",
  "163": "Onde Gerninger, som er til Skade for en selv, de er lette at udføre; men en god og heldbringende Gerning er overmaade vanskelig.",
  "164": "Den Taabe, der foragter de helliges, de ædles og de retsindiges Lærdomme og følger falsk Lære, han sætter Frugt til sin egen Fordærv ligesom Katthaka-røret.",
  "165": "Det er ens eget Jeg, der handler ondt, og som føler Smerte; eller det er ens eget Jeg, der ikke handler ondt, og som er rent; Renhed og Urenhed beror paa en selv; den ene kan ikke gøre den anden ren.",
  "166": "Ikke skal man opgive sin egen Sag af Hensyn til andres, hvor vigtig den end kan være; naar man har vundet Klarhed over sin egen Sag, saa skal man holde fast ved den.",
  "chap13": "Verden",
  "167": "Man skal ikke følge daarlig Lære, ikke leve i Slaphed, ikke hylde falsk Tænkning, ikke fremme Verden.",
  "168": "Man skal rejse sig, ikke falde hen i Slaphed; man skal følge et pligtopfyldende Livs Lov; den der lever efter Loven, han hviler i Lykke i denne Verden og hisset.",
  "169": "Man skal følge et pligtopfyldende Livs Lov, ikke et slet Livs; den der lever efter Loven, han hviler i Lykke i denne Verden og hisset.",
  "170": "Man betragte Verden som en Boble, man betragte den som en Luftspejling; den der ser saadan ned paa Verden, ham faar Dødens Fyrste ikke Øje paa.",
  "171": "Kom, se paa denne Verden, broget som en Fyrstes Vogn; hvor Daarerne fortvivler, men som de vise ingen Berøring har med.",
  "172": "Den der før var slap, men senere opgav sin Slaphed, som Maanen fra en skyfri Himmel faar han denne Verden til at straale.",
  "173": "Den hvis onde Gerninger overskygges af de gode, som Maanen fra en skyfri Himmel faar han denne Verden til at straale.",
  "174": "Denne Verden er Mørke, kun faa formaar at se her; kun faa gaar mod Himlen som Fuglen, der er undsluppet Nættet.",
  "175": "Vandregæssene drager ad Solens Veje; de vise Mænd gaar med overmenneskelig Kraft gennem Rummet; de føres bort fra denne Verden, naar Mâra og hans Hær er besejret.",
  "176": "Det Menneske, som har overtraadt blot ét Bud, og som taler Usandhed og lader haant om den hinsidige Verden, han er i Stand til enhver ond Gerning.",
  "177": "De gerrige gaar ikke til Gudernes Verden; kun Taaberne priser ikke Gavmildhed; den vise føler Glæde ved at give, og derved bliver han lykkelig hisset.",
  "178": "Mere end Herredømmet over Jorden, mere end Adgang til Himlen, mere end Magten over alle Verdener opnaar den, der er naaet ind i Strømmen.",
  "chap14": "Buddhaen (Den Vakte)",
  "179": "Han hvis Sejr ikke kan besejres, og som ingen i Verden kan vinde Sejr over, Buddhaen, hvis Erkendelse er uden Grænser, ad hvilken Vej vil I føre ham, den vejløse?",
  "180": "Han hvem Begæret med dets Snarer og Lyst ikke formaar at føre nogetsteds hen, Buddhaen, hvis Erkendelse er uden Grænser, ad hvilken Vej vil I føre ham, den vejløse?",
  "181": "Selv Guderne misunder dem, der helt helliger sig Tankens Fæstnen; dem der er vise og finder deres Glæde i Forsagelsens Hvile; dem som er fuldstændig vakte og har Hold paa deres Tanker.",
  "182": "Vanskelig er et Menneskes Undfangelse, vanskelig er de dødeliges Liv, vanskelig er det at lytte til den sande Lære, vanskeligt kommer en Buddha til Verden.",
  "183": "At afholde sig fra alle onde Gerninger, at lægge sig efter de gode, at holde sin Tanke ren, det er Buddhaernes Lære.",
  "184": "Overbærenhed er den højeste Bodsøvelse, Taalmod det højeste Nirvâna, siger Buddhaerne; den der saarer andre, er ingen hellig Mand, den der krænker andre, ingen Buddha-lærling.",
  "185": "Ikke at smæde andre, ikke at saare andre, Underkastelse under Loven, Maadehold overfor Spise, at ligge eller sidde for sig selv, Øvelse i Tankens Anspændelse, det er Buddhaernes Lære.",
  "186": "Om det saa regnede med Guldstykker, vilde man ikke finde Tilfredsstillelse i Nydelser; smertefyldte er Nydelserne og bringer kun kortvarig Glæde, det indser den vise Mand;",
  "187": "han finder ingen Glæde selv i himmelske Nydelser; Buddhaernes Lærling glæder sig kun ved Begærets Ophør.",
  "188": "Mennesker, der skælver af Frygt, søger mange Slags Tilflugtsteder: Bjerge, Skove, hellige Lunde og Træer;",
  "189": "men disse er ikke noget sikkert Tilflugtsted; de er ikke det bedste Tilflugtsted; den der naar et saadant Tilflugtsted, han er dog ikke frelst fra alle Lidelser.",
  "190": "Den der søger Tilflugt hos Buddha, hans Lære og hans Orden; den som tilfulde forstaar de fire ædle Sandheder:",
  "191": "Lidelsen, Lidelsens Oprindelse, Lidelsens Overvindelse og den hellige otteleddede Vej, som fører til Lidelsens Ophør;",
  "192": "det er et sikkert Tilflugtsted; det er det bedste Tilflugtsted; den der naar det Tilflugtsted, han er frelst fra alle Lidelser.",
  "193": "En saadan ædel Mand er svær at finde, han fødes ikke hvor som helst; men hvor en saadan vis Mand fødes, der vokser Slægten i Lykke.",
  "194": "Lykke bringer Buddhaernes Fødsel; Lykke bringer deres Belæring i den sande Lære; Lykke bringer Ordenens Samdrægtighed; Lykke bringer de samdrægtiges Andagt.",
  "195": "De der ærer de ærværdige, Buddhaerne og deres Lærlinge, som har arbejdet sig ud af Blændværket og lagt Sorger og Bekymringer bag sig;",
  "196": "de der ærer saadanne Mænd, som har naaet Nirvâna og er uden Frygt, de vinder større Fortjeneste, end nogen kan forestille sig.",
  "chap15": "Lykken",
  "197": "Lykkeligt lever vi i Sandhed uden Had blandt de hadende; blandt hadefulde Mennesker bor vi uden Had.",
  "198": "Lykkeligt lever vi i Sandhed uden Lidelser blandt de lidende; blandt lidende Mennesker bor vi uden Lidelser.",
  "199": "Lykkeligt lever vi i Sandhed uden Begær blandt de begærlige; blandt begærlige Mennesker bor vi uden Begær.",
  "200": "Lykkeligt lever vi i Sandhed, vi som intet ejer; vor Lykke skal være vor Næring ligesom hos de straalende Guder.",
  "201": "Sejr avler Had, thi den besejrede lever i Lidelse; lykkeligt lever den, der er faldet til Ro og har ladet Sejr og Nederlag bag sig.",
  "202": "Der er ingen Ild som Begæret; ingen Ulykke som Hadet; ingen Lidelse som den personlige Tilværelse; ingen Lykke højere end Sindets Ro.",
  "203": "Sult er den værste Sygdom; Spirerne til nyt Liv den største Lidelse; den der har forstaaet dette til Bunds, anser Nirvana for den højeste Lykke.",
  "204": "Sundhed er den højeste Vinding; Tilfredshed den største Skat; Tillid den bedste Frænde; Nirvana den højeste Lykke.",
  "205": "Den der har drukket Ensomhedens og Roens Sødme, han er uden Frygt og uden Synd, naar han inddrikker den sande Læres søde Læskedrik.",
  "206": "Velgørende er Synet af de ædle, Livet hos dem bringer altid Lykke; ved ikke at se Taaberne vil man altid føle sig lykkelig.",
  "207": "Den der følges med Taaber, ham plager den lange Vej; ulykkebringende er altid Livet hos Taaber som hos Fjender; at leve hos vise Mænd er lykkeligt som det at træffe Frænder.",
  "208": "Man skal følge den vise, den forstandige, den lærde, den udholdende, den fromme, den ædle; en saadan god og klog Mand skal man følge som Maanen følger Stjernebilledernes Vej.",
  "chap16": "Det Vi Holder Af",
  "209": "Den der lægger sig efter forfængelig Stræben uden at beflitte sig paa Anspændelse; den som opgiver, hvad der tjener til hans Vel, og griber efter det, hans Lyst staar til, han maa misunde den, der anspænder sit Jeg.",
  "210": "Aldrig nogensinde skal man søge Berøring med, hvad der er én kært, eller hvad der er én ukært; Lidelse er det, ikke at se, hvad der er én kært, eller at se, hvad der er én ukært.",
  "211": "Derfor skal man ikke fatte Kærlighed til noget, thi Tabet af det, man holder af, bringer Sorg; den der hverken føler Kærlighed eller Had til noget, han er uden Baand.",
  "212": "Af det, man holder af, avles Bekymring; af det, man holder af, avles Frygt; den der har frigjort sig fra at holde af noget, han kender hverken Bekymring eller Frygt.",
  "213": "Kærlighed avler Bekymring, Kærlighed avler Frygt; den der har frigjort sig fra Kærlighed, kender hverken Bekymring eller Frygt.",
  "214": "Lyst avler Bekymring, Lyst avler Frygt; den der har frigjort sig fra Lyst, kender hverken Bekymring eller Frygt.",
  "215": "Elskov avler Bekymring, Elskov avler Frygt; den der har frigjort sig fra Elskov, kender hverken Bekymring eller Frygt.",
  "216": "Begær avler Bekymring, Begær avler Frygt; den der har frigjort sig fra Begær, kender hverken Bekymring eller Frygt.",
  "217": "Den der er god og klog, retsindig og sandhedskærlig; den som passer sine egne Sager, ham holder Mennesker af.",
  "218": "Den der er fuld af Lyst efter det uudsigelige; den som fyldes helt af Tanken; den hvis Tanke ikke er bundet af Begær, han kaldes en, som Strømmen fører opad.",
  "219": "Den der har været længe borte og som velbeholden kommer tilbage langvejs fra, hans Komme hilser Slægt, Venner og Paarørende;",
  "220": "saadan modtager de gode Gerninger den, der har handlet godt, naar han gaar fra denne Verden til den næste, ligesom Slægtninge en kær Gæst.",
  "chap17": "Vrede",
  "221": "Man skal lade Vreden fare og opgive Hovmod; man skal arbejde sig ud over enhver Tilknytning; den der ikke hæfter sig ved Navn og Form og ikke kalder noget sit, ham følger Lidelserne ikke.",
  "222": "Den der standser den opblussende Vrede ligesom en rullende Vogn, ham kalder jeg en virkelig Vognstyrer; de andre holder kun Tøjlerne.",
  "223": "Med Mildhed skal man besejre Vreden, med godt skal man besejre ondt, med Gavmildhed skal man besejre den gerrige, med Sandhed den, der taler usandt.",
  "224": "Sandhed skal man tale; ikke vredes; og give, naar man anmodes om en ringe Gave: ved disse tre Ting nærmer man sig Guderne.",
  "225": "De Vismænd, som ikke tilføjer nogen Skade, og som altid holder deres Legeme i Tømme, de gaar til den evige Hvile, hvor ingen Sorg rammer dem.",
  "226": "De der altid vaager; som forsker Dag og Nat, og som stræber mod Nirvâna, hos dem svinder de onde Indflydelser.",
  "227": "Det er et gammelt Ord, Atula, og ikke blot fra idag: man dadler den, der sidder tavs; man dadler den, der taler meget; man dadler den, der taler lidt; ingen undgaar Dadel her i Verden.",
  "228": "Der har aldrig været, der vil aldrig være, og der findes ikke nu noget Menneske, der udelukkende dadles, eller som udelukkende prises.",
  "229": "Men den, som de kloge priser, idet de prøver ham Dag for Dag; den der lever ulasteligt; den som er vis, forstandig og god,",
  "230": "den der er som præget i Guld fra Jambû-floden; hvem tør dadle ham? Selv Guderne priser ham; selv af Brahman prises han.",
  "231": "Man vogte sig for at handle i Vrede; man skal holde sit Legeme i Tømme; man skal undlade onde Handlinger og øve godt med sit Legeme.",
  "232": "Man vogte sig for at tale i Vrede; man skal holde sin Tale i Tømme; man skal undlade ond Tale og øve godt med sin Tale.",
  "233": "Man vogte sig for at tænke i Vrede; man skal holde sin Tanke i Tømme; man skal undlade ond Tanke og øve godt med sin Tanke.",
  "234": "De vise Mænd, som holder deres Legeme i Tømme; som holder deres Tale i Tømme, og som holder deres Tanke i Tømme; de vise holder sig i Sandhed godt i Tømme.",
  "chap18": "Smuds",
  "235": "Du er nu som et vissent Blad; Yamas Sendebud har indfundet sig; Du staar ved Rejsens Begyndelse, og Du har ingen Rejsekost.",
  "236": "Bered en Ø for Dig selv; stræng Dig hurtigt an og bliv vis! Naar Dit Smuds er pustet væk, og Du er uden Synd, kommer Du til de ædles himmelske Verden.",
  "237": "Dit Liv nærmer sig nu sin Ende; Du er kommet Yama nær; der findes intet Opholdssted undervejs, og Du har ingen Rejsekost.",
  "238": "Bered en Ø for Dig selv; stræng Dig hurtigt an og bliv vis! Naar Dit Smuds er pustet væk, og Du er uden Synd, er Du ikke mere underkastet Fødsel og Alderdom.",
  "239": "Den vise skal puste Smudset væk fra sig ligesom Sølvsmeden puster det fra Sølvet, Plet for Plet, lidt efter lidt, fra Tid til anden.",
  "240": "Ligesom de Rustpletter, der fremkommer paa Jern, æder det sønder, hvis de fremkommer fra Jernet selv, saaledes fører Synderens Gerninger ham selv til Helvede.",
  "241": "De hellige Tekster plettes, hvis man ikke fordyber sig i dem; Husvæsen plettes af Dovenskab; et kønt Ydre plettes af Ørkesløshed; den aarvaagne plettes af Slaphed.",
  "242": "En Kvinde plettes af slet Vandel; den der skal give, plettes af Havesyge; onde Sæder er Pletter baade i denne Verden og hisset.",
  "243": "Der er Pletter mere smudsige end disse; Uvidenhed er den værste Plet; gør Eder fri for den Plet, saa er I pletfri, Tiggermunke!",
  "244": "Livet er let at leve for den skamløse, for den der er fræk som en Krage, for den paagaaaende, opblæste og fordærvede Mand.",
  "245": "Livet er vanskeligt at leve for den, der føler Undseelse, for den der altid søger Renhed, for den der ikke trænger sig paa, for den beskedne, pletfri og omsorgsfulde Mand.",
  "246": "Den der her i Verden dræber Liv, fører falsk Tale, tager hvad der ikke er givet ham, eller gaar til anden Mands Hustru,",
  "247": "eller den Mand, som er hengiven til Brændevin og stærke Drikke, han graver sin Rod op allerede her i Verden.",
  "248": "Vid dette, Menneske! De der ikke holder sig selv i Tømme, de er i en daarlig Forfatning; lad ikke Begær og Synd udsætte Dig for Lidelse i lange Tider.",
  "249": "Menneskene giver Almisse efter deres Tro og efter den Tilfredsstillelse, de føler derved; hvis man derfor føler Bitterhed paa Grund af andres Mad og Drikke, saa finder man hverken Sindsro ved Dag eller Nat.",
  "250": "Den, hos hvem denne Følelse er fjernet og rykket op med Rode, han finder Sindsro baade ved Dag og Nat.",
  "251": "Der er ingen Ild som Lidenskaben; der er ingen Drage som Hadet; der er ingen Snare som Forblindelsen; der er ingen Flod som Begæret.",
  "252": "Andres Fejl er lette at se; sine egne faar man vanskeligt Øje paa; andres Fejl spreder man ligesom Avner; men sine egne tilslører man, ligesom Falskspilleren skjuler et uheldigt Terningkast for sin Modspiller.",
  "253": "Den der spejder efter andres Fejl og altid er tilbøjelig til at føle sig saaret, hos ham vokser de onde Indflydelser, og deres Tilintetgørelse er fjern.",
  "254": "Ligesom der ingen Spor findes i Rummet, er der ingen Asketer udenfor Ordenen; Menneskene glæder sig ved Verdens Tant; de fuldkomne har frigjort sig herfor.",
  "255": "Ligesom der ingen Spor findes i Rummet, er der ingen Asketer udenfor Ordenen; alle Tilværelser er forgængelige; Buddhaerne kan intet bevæge.",
  "chap19": "Den Retsindige",
  "256": "Retsindig bliver man ikke ved at føre sin Sag igennem med Vold; men den der kyndigt forstaar at skelne mellem Ret og Uret,",
  "257": "og som fører andre, ikke med Vold, men med ligelig Ret, som en klog Rettens Vogter, han kaldes retsindig.",
  "258": "Vis bliver man ikke ved at tale mange Ord; den der er taalsom, mild og frygtløs, han kaldes vis.",
  "259": "En Hævder af Ret bliver man ikke ved at tale mange Ord; selv om man kun har lært lidet, men har en umiddelbar Forstaaelse af Retten, saa er man en Hævder af Ret, en som ikke forsømmer Retten.",
  "260": "En af 'Menighedens Ældste' bliver man ikke ved at ens Haar graaner; ens Alder kan være fremskreden, og alligevel kan man kaldes en, der er bleven gammel til ingen Nytte.",
  "261": "Den hos hvem man finder Sandhed, Ret, Skaansomhed, Tugt og Selvbeherskelse; den som har udspyet alt Smuds og er vis, han regnes blandt 'Menighedens Ældste'.",
  "262": "Ikke blot ved at gøre mange Ord eller ved et smukt Ydre bliver den misundelige, havesyge og uærlige Mand en brav Mand;",
  "263": "men den, hos hvem alt dette er fjernet og rykket op med Rode, den som har udspyet alt Had og er vis, han kaldes en brav Mand.",
  "264": "Den der ikke er pligtopfyldende og som taler usandt, han bliver ikke en Buddha-lærling ved at rage Hovedet: kan en Buddha-lærling være opfyldt af Begær og Attraa?",
  "265": "Men den der dæmper det onde, smaat og stort, alt til Hobe, han kaldes en Buddha-lærling, fordi han dæmper det onde.",
  "266": "Tiggermunk bliver man ikke blot ved at tigge hos andre; ikke derved, men ved at optage hele den sande Lære i sig, bliver man Tiggermunk.",
  "267": "Den som er hinsides godt og ondt; den som er kysk; den som under Betragtninger vandrer gennem Verden, han kaldes i Sandhed en Tiggermunk.",
  "268": "En Vismand bliver man ikke ved Tavshed, naar man er taabelig og uvidende; men den der ligesom paa en Vægt kyndigt vælger det gode",
  "269": "og lader det onde ligge, han er en Vismand; derved er han en Vismand. Den som kender begge Verdener, han kaldes en Vismand.",
  "270": "En ædel Mand bliver man ikke ved at skade andres Liv; ved Skaansomhed overfor alt Liv opnaar man at kaldes en ædel Mand.",
  "271": "Ikke blot ved at opfylde de hellige Handlinger, ikke ved megen Lærdom, ikke ved Tankens Fæstnen, ikke ved at leve afsides fra andre",
  "272": "vinder jeg den Forsagelsens Lykke, som Verdens Børn ikke kender. I Tiggermunke, bliv ikke for tillidsfulde, før I har standset de onde Indflydelser!",
  "chap20": "Vejen",
  "273": "Den bedste af alle Veje er den otteleddede Vej; den bedste af alle Sandheder er de fire Ord; den bedste af alle gode Ting er Forsagelsen; den bedste af alle Mænd er den, der forstaar at se.",
  "274": "Det er Vejen; der er ingen anden til at klargøre Anskuelsen; følg den! Verden her er Mâras Blændværk.",
  "275": "Naar I gaar ad den Vej, saa gør I Ende paa Lidelsen. Den Vej har jeg forkyndt, da jeg havde lært at fjerne Tornen.",
  "276": "I selv maa spænde Eder an; de fuldkomne viser kun Vejen; de der med fæstnet Tanke følger den, de befries fra Mâras Baand.",
  "277": "Alle Foreteelser er forgængelige; den der forstaar og erkender det, han bliver ligegyldig overfor Lidelsen; det er Vejen til Klarhed.",
  "278": "Alle Foreteelser er Lidelse; den der forstaar og erkender det, han bliver ligegyldig overfor Lidelsen; det er Vejen til Klarhed.",
  "279": "Alle Foreteelser er indholdsløse; den der forstaar og erkender det, han bliver ligegyldig overfor Lidelsen; det er Vejen til Klarhed.",
  "280": "Den der ikke staar op, naar det er Tid at staa op; den som skønt ung og kraftig er forfalden til Sløjhed; den hvis Vilje og Tanke er sløvet, en saadan ørkesløs og sløj Mand finder aldrig Vejen til Erkendelse.",
  "281": "Vogtende vel paa sin Tale og med sin Tanke i Tømme se man til aldrig at begaa noget ondt med sit Legeme; disse tre Handlingens Veje skal man holde rene, saa vil man kunne fuldføre den Vej, de vise har forkyndt.",
  "282": "Ved Anspændelse opstaar Erkendelse, ved Sløvhed svinder den; den der kender denne tvedelte Vej til Vinding og til Tab, han skal føre sig selv saadan, at Erkendelsen vokser.",
  "283": "Fæld hele Skoven, ikke et enkelt Træ; fra Skoven kommer Farerne! Naar I har fældet Skoven og Begæret, saa er I frigjort Tiggermunke!",
  "284": "Saa længe en Mands Begær efter Kvinder, selv det ringeste, ikke er brudt, saa længe er hans Tanke bundet, ligesom en diende Kalv hos sin Moder.",
  "285": "Bryd Kærligheden til Dit eget Jeg, ligesom Du med Haanden bryder Efteraarets Lotus; vælg Vejen til Fred, til Nirvâna, den som Buddha har anvist.",
  "286": "'Her vil jeg bo i Regntiden, her ved Vinter- og Sommertid'; saadan overvejer Taaben og tænker ikke paa Døden.",
  "287": "Døden fører med sig en Mand, der er optaget af Sønner og Kvæg, og hvis Tanke er andetsteds, ligesom Floden den sovende Landsby.",
  "288": "Da er Sønner ingen Hjælp til, eller en Fader eller Slægtninge; den som Døden har grebet, han finder ingen Beskyttelse hos sine Paarørende.",
  "289": "Den kloge, gode og selvbeherskede Mand, som forstaar Betydningen af dette, han vil hurtigt berede den Vej, der fører til Nirvâna.",
  "chap21": "Forskelligt",
  "290": "Hvis man ved Opgivelse af en ringe Lykke har Udsigt til en stor Lykke, saa skal den vise Mand opgive den ringe Lykke og rette Blikket mod den store Lykke.",
  "291": "Den der for sig ønsker Lykke, der medfører Ulykke for andre, han vil blive hildet i Hadets Lænker og aldrig befries fra Had.",
  "292": "Med Tilsidesættelse af sine Pligter gør man det, man hellere skulde undlade; hos slette eller slappe Mennesker vokser de onde Indflydelser.",
  "293": "Men de, hvis Tanke altid i Anspændelse er rettet paa deres Legeme, de gør ikke, hvad de ikke maa, men altid det, de skal gøre; hos anspændte og forstandige Mennesker svinder de onde Indflydelser.",
  "294": "En Brahman bliver ved at være uden Skyld, selv om han har dræbt Moder og Fader, to Konger af Krigerkasten og et helt Rige med alt, hvad dertil hører.",
  "295": "En Brahman bliver ved at være uden Skyld, selv om han har dræbt Fader og Moder, to Konger af Brahmankasten og den ypperste Mand som Nummer fem.",
  "296": "Altid aarvaagne og vagtsomme er Gotamas Tilhængere, hvis Tanke Dag og Nat uden Ophør er rettet paa Buddha.",
  "297": "Altid aarvaagne og vagtsomme er Gotamas Tilhængere, hvis Tanke Dag og Nat uden Ophør er rettet paa den sande Lære.",
  "298": "Altid aarvaagne og vagtsomme er Gotamas Tilhængere, hvis Tanke Dag og Nat uden Ophør er rettet paa Ordenen.",
  "299": "Altid aarvaagne og vagtsomme er Gotamas Tilhængere, hvis Tanke Dag og Nat uden Ophør er rettet paa deres Legeme.",
  "300": "Altid aarvaagne og vagtsomme er Gotamas Tilhængere, hvis Tanke Dag og Nat føler Glæde ved Skaansomhed.",
  "301": "Altid aarvaagne og vagtsomme er Gotamas Tilhængere, hvis Tanke Dag og Nat føler Glæde ved Tankens Fæstnen.",
  "302": "Svær er Forsagelsen, svært er det at føle Glæde, svært er det at leve i Hjemmets Lidelser, svært er det at leve blandt Ligemænd, Lidelse rammer Vandringsmanden; derfor skal man ikke blive Vandringsmand og ikke lade sig ramme af Lidelse.",
  "303": "Den der er troende og har et godt Sind og er udrustet med Ære og Rigdom, han æres overalt, hvilket Sted han end slaar sig ned.",
  "304": "Gode Mennesker lyser paa lang Afstand ligesom sneklædte Bjærge; onde Mennesker er ikke engang synlige nærved, ligesom Pile afskudt i Natten.",
  "305": "Den der sidder i Ensomhed og ligger i Ensomhed og uden Ophør vandrer i Ensomhed; den der i Ensomhed holder sit Jeg i Tømme, han vil føle sig lykkelig i Skovkanten.",
  "chap22": "Helvede",
  "306": "Den der taler usandt, gaar til Helvede, og den, der efter at have gjort en Ting, nægter den; efter Døden er de begge lige; hisset er de Mennesker, der har begaaet onde Gerninger.",
  "307": "Mange, der bærer den gule Munkekutte, er dog onde og uden Hold paa sig selv; disse onde Mennesker gaar til Helvede paa Grund af deres onde Gerninger.",
  "308": "Bedre er det at sluge en Jernkugle glødende som Ildens Flammer end som en slet og ubehersket Mand at leve af Landets Tiggergaver.",
  "309": "Fire Ting opnaar en letsindig Mand, der nærmer sig en andens Hustru; han paadrager sig Skyld, et uroligt Leje, for det tredje Vanære og for det fjerde Helvede.",
  "310": "Han paadrager sig Skyld, han gaar til Helvede, frygtsom hos en frygtsom Kvinde opnaar han kun en kort Lyst, og Kongen paalægger ham haard Straf; derfor skal en Mand ikke nærme sig en andens Hustru.",
  "311": "Ligesom Kusa-Græs, naar man tager forkert paa det, skærer én i Haanden, saaledes fører det at misbruge sin Stilling som Buddhas Lærling til Helvede.",
  "312": "Enhver skødesløs Handling, uren Overholdelse af hellige Pligter, tvivlsom Kyskhed, alt det bringer kun ringe Frugt.",
  "313": "Hvad der er ens Pligt, det skal man gøre og tage fat paa det med Fasthed; en skødesløs Asket spreder Urenhed videre omkring.",
  "314": "En ond Gerning skal man helst lade ugjort, bagefter angrer man den onde Gerning; en god Gerning skal man helst faa gjort, den angrer man ikke.",
  "315": "Som en Grænsefæstning, vel vogtet ude og inde, saaledes skal man vogte sig selv; ikke et Øjeblik maa forsømmes; de, der har forsømt det rette Øjeblik, lider, naar de er i Helvede.",
  "316": "De Mennesker, som føler Skam ved det, de ikke behøver at skamme sig for, men som ikke føler Skam ved det, de skulde skamme sig for, de hylder falsk Lære og gaar til Helvede.",
  "317": "De Mennesker, som frygter, hvor der ikke er noget at frygte, og som ikke frygter, hvor der er noget at frygte, de hylder falsk Lære og gaar til Helvede.",
  "318": "De Mennesker, som finder Synd, hvor der ikke er nogen Synd, og som ikke finder Synd, hvor der er Synd, de hylder falsk Lære og gaar til Helvede.",
  "319": "De Mennesker, der anser for Synd det, der er Synd, og ikke anser for Synd det, der ikke er Synd, de hylder den sande Lære og gaar til Himlen.",
  "chap23": "Elefanten",
  "320": "Som en Elefant maa kunne taale den i Slaget fra Buen afskudte Pil, saaledes maatte jeg finde mig i Forhaanelser, thi Mængden er slet.",
  "321": "Tæmmet føres den til Slaget, tæmmet bestiges den af Kongen; den der er tæmmet, er den bedste blandt Mennesker, den der finder sig i Forhaanelser.",
  "322": "Tæmmede Muldyr er gode og ædle Sindhu-Heste og vældige Elefanter; men endnu bedre er den, der tæmmer sit Jeg.",
  "323": "Thi med disse Forspand kommer man ikke til Uforgængelighedens Land, hvortil man tæmmet naar paa et tæmmet Dyr, sit eget velttæmmede Jeg.",
  "324": "Elefanten Dhânapalaka, den ustyrlige med den skarpe Brunstvædske, den æder ikke en Mundfuld, naar den er bundet; Elefanten mindes Bjergskoven.",
  "325": "Den der er fed og en stor Æder, og som søvndrukken vender sig paa sit Leje, han er som et Svin, der fedes op med Korn; den Taabe vil atter og atter blive genfødt.",
  "326": "Min Tanke vandrede tidligere omkring, som den lystede, som den vilde, som den fandt for godt; den vil jeg nu holde fast til Gavns, som Elefantvogteren den brunstige Elefant.",
  "327": "Fald ikke hen i Slaphed, vogt Eders Tanke; red Eder selv op af Uføret som en Elefant, der er faldet i en Sump.",
  "328": "Hvis man træffer en klog Ledsager, en kyndig Mand, som lever retsindigt og vil slaa Følge, saa skal man vandre sammen med ham glad og selvbehersket, idet man overvinder alle Hindringer.",
  "329": "Hvis man ikke træffer en klog Ledsager, en kyndig Mand, som lever retsindigt og vil slaa Følge, saa skal man, ligesom en Konge, der forlader sit tabte Land, vandre alene som en Elefant i Skoven.",
  "330": "Det er bedst at vandre alene, Daarer er intet Følgeskab; alene skal man vandre og afholde sig fra ondt, glad ved lidet, som en Elefant i Skoven.",
  "331": "Naar en Retssag kommer op, er Venner en Lykke; Tilfredshed er en Lykke, hvad den saa skyldes; gode Gerninger er en Lykke, naar Livet svinder; at afholde sig fra alt ondt er en Lykke.",
  "332": "Lykke er det at være Moder her i Verden, en Lykke at være Fader; en Lykke er det at være Buddhas Lærling her i Verden, en Lykke at være Brahman.",
  "333": "En Lykke er Godhed, der varer til Alderdommen; en Lykke er urokkelig Tro; en Lykke er det at vinde Erkendelse; en Lykke ikke at handle ondt.",
  "chap24": "Begær",
  "334": "Hos et Menneske, der lever uden Hold paa sig selv, vokser Begæret som en Slyngplante; han gaar fra den ene Tilværelse til den anden som en Abe, der søger Frugter i Skoven.",
  "335": "Den hvem det voldsomme Begær med dets Lyst her i Verden besejrer, hans Bekymringer vokser, ligesom Bîrana-Græs breder sig.",
  "336": "Men den som besejrer det voldsomme Begær, der er saa svært at overvinde her i Verden, hans Bekymringer falder bort, ligesom Vanddraaben falder fra Lotusbladet.",
  "337": "Lad mig sige dette til Eder, der er forsamlede her: Grav Begæret op med Rode, ligesom den der ønsker Usîra, graver Bîrana-Græsset op; at ikke Mâra Gang paa Gang skal knække Eder som Floden Rørene.",
  "338": "Som et Træ vokser op igen, selv om det er fældet, naar blot Roden er uskadt og fast, saaledes spirer Lidelsen atter og atter frem, saalænge al Vedhængen ved Begæret ikke er ødelagt.",
  "339": "Den hvis seksogtredive Strømme voldsomt flyder med Lyst, ham vil Bølgerne hans Ønsker rettet mod Attraa rive med sig, den Taabe.",
  "340": "Strømmene flyder allevegne; Slyngplanten staar og skyder i Vejret; naar I ser den spire frem, saa hug Roden over med Erkendelsens Hjælp.",
  "341": "Menneskets Glæder er urolige og lystfyldte; hengivne til Fornøjelser og søgende Lyst er de underkastede Fødsel og Alderdom.",
  "342": "Beherskede af Begær farer Menneskene rundt som en fangen Hare; bundne i Baand og Lænker henfalder de atter og atter til Lidelse for lang Tid.",
  "343": "Beherskede af Begær farer Menneskene rundt som en fangen Hare; derfor skal Tiggermunken jage Begæret bort, hvis han ønsker sig Forsagelse.",
  "344": "Den der, fri for Begær, atter hælder mod Begær; den som skønt frelst fra Begær atter giver sig Begæret i Vold, se paa den Mand! Befriet giver han sig atter under Lænker.",
  "345": "Vise Mænd kalder ikke det en stærk Lænke, som er lavet af Jern, Træ eller Hamp; men det lidenskabelige Begær efter Ædelstene, Ringe, Sønner eller Hustruer,",
  "346": "det kalder vise Mænd en stærk Lænke, en der drager ned, en som føles let, men er svær at løsne; naar Mennesker har brudt den, drager de afsted som Munke uden Savn og med Attraaens Glæder ladt bag sig.",
  "347": "De som er hengivne til Attraa, følger Strømmen, ligesom Edderkoppen det Net, den selv har spundet; naar Mennesker har brudt dens Magt, drager de afsted uden Savn og med alle Lidelser ladt bag sig.",
  "348": "Opgiv, hvad der ligger forud; opgiv, hvad der følger efter; opgiv, hvad der er imellem, naar Du gaar til den anden Side af Tilværelsen; naar Du helt har gjort Din Tanke fri, vil Du ikke mere være underkastet Fødsel og Alderdom.",
  "349": "Hos et Menneske, der rystes af Tvivl, som er fuld af Begær og kun søger Lyst, vokser Begæret mere og mere; han gør i Sandhed den Lænke, der binder ham, stærk.",
  "350": "Naar et Menneske glæder sig ved, at hans Tvivl er faldet til Ro, og under stadig Betragtning forestiller sig, hvad der ikke vækker Lyst, saa vil han i Sandhed fjerne Mâras Lænker, ja bryde dem helt.",
  "351": "Den der har naaet Maalet; den som ikke skælver, men er uden Begær og uden Synd, han har fernet Tilværelsens Torne; han oplever sin sidste Tilværelse.",
  "352": "Den som er uden Begær og uden Attraa; den som er kyndig i de hellige Skrifters Sprog; den som kender Stavelsernes Sammenføjning og rigtige Rækkefølge, han er for sidste Gang iklædt et Legeme og kaldes en højvis Mand.",
  "353": "Jeg har overvundet alt; jeg ved alt; i alle Forhold er jeg uden Lyde; alt har jeg ladt bag mig; ved Begærets Ophør er jeg frigjort; selv har jeg vundet Erkendelse; hvem skal jeg belære?",
  "354": "Den sande Læres Gave overgaar al anden Gave; den sande Læres Sødme overgaar al anden Sødme; Glæden ved den sande Lære overgaar al anden Glæde; Begærets Ophør besejrer al Lidelse.",
  "355": "Nydelserne dræber Taaben, hvis han ikke søger det hinsidige; ved sit Begær efter Nydelser dræber Taaben sig selv saavel som andre.",
  "356": "Markerne ødelægges af Ukrudt, Mængden her af Attraa; derfor bærer en Gave til de forsagende stor Frugt.",
  "357": "Markerne ødelægges af Ukrudt, Mængden her af Had; derfor bærer en Gave til de hadefri stor Frugt.",
  "358": "Markerne ødelægges af Ukrudt, Mængden her af Forblindelse; derfor bærer en Gave til de klartseende stor Frugt.",
  "359": "Markerne ødelægges af Ukrudt, Mængden her af Begær; derfor bærer en Gave til dem, der er uden Begær, stor Frugt.",
  "chap25": "Tiggermunken",
  "360": "Godt er det at holde Øjet i Tømme, godt at holde Øret i Tømme, godt at holde Næsen i Tømme, godt at holde Tungen i Tømme.",
  "361": "Godt er det at holde Legemet i Tømme, godt at holde sin Tale i Tømme, godt at holde Tanken i Tømme, godt at holde sig i Tømme overfor alt. Den Tiggermunk, som holder sig i Tømme overfor alt, han frelses fra al Lidelse.",
  "362": "Den der behersker sin Haand og behersker sin Fod; den som behersker sin Tale; den ypperste af alle selvbeherskede; den som føler den indre Glæde og har Hold paa sin Tanke; den som er tilfreds i Ensomhed, ham kalder jeg en Tiggermunk.",
  "363": "Den Tiggermunk, som holder sin Mund i Tømme; som taler klogt og beskedent; som lærer det sande og det gode, hans Tale er sød.",
  "364": "Den Tiggermunk, som lever i den sande Lære; som glæder sig ved den sande Lære; som tænker over den sande Lære; som fordyber sig i den sande Lære, han falder ikke fra den sande Lære.",
  "365": "Han maa ikke ringeagte det, han har faaet, og ikke misunde andre; den Tiggermunk, der misunder andre, han faar ikke Ro i Sindet.",
  "366": "Den Tiggermunk, der har faaet en ringe Gave og ikke ringeagter den, ham priser selv Guderne, hvis hans Vandel er ren og ihærdig.",
  "367": "Den der fuldstændig er blottet for Begær efter Navn og Form, og som ikke sørger over, hvad der ikke er, han kaldes med Rette en Tiggermunk.",
  "368": "Den Tiggermunk, som optræder venligt, og som finder sin Lykke i Buddhas Lære, han kommer til et fredet Sted, Lykken ved at Spirerne til nyt Liv er falden til Ro.",
  "369": "Tøm denne Baad, Tiggermunk! Naar den er tømt, vil den gaa lettere; naar Du har brudt Attraaen og Hadets Magt, kommer Du til Nirvâna.",
  "370": "Bryd de fem, opgiv de fem, slet de fem fuldstændig ud; den Tiggermunk, som er undsluppet de fem Lænker, kaldes en, der er frelst fra Strømmen.",
  "371": "Anspænd din Tanke, Tiggermunk, og vogt Dig for Slaphed; lad ikke Din Tanke dvæle ved sanselig Lyst, at Du ikke i Din Mangel paa Agtpaagivenhed vil komme til at sluge en Jernkugle, og ikke, naar Du brændes, skal klage: Dette er Lidelse.",
  "372": "Den der ikke er i Besiddelse af Erkendelse, ejer heller ikke en fæstnet Tanke; den der ikke er i Besiddelse af en fæstnet Tanke, ejer heller ikke Erkendelse; den der ejer baade Erkendelse og fæstnet Tanke, han er i Sandhed Nirvâna nær.",
  "373": "Den Tiggermunk, som er gaaet ind i sit tomme Hus, og hvis Tanke er faldet til Ro, han føler en overmenneskelig Glæde, idet han ret erkender den sande Lære.",
  "374": "Saasnart han gennemskuer den personlige Tilværelses Fremkomst og Undergang, føler han en Fryd og Glæde som hos dem, der kender Udødeligheden.",
  "375": "Herredømme over Sanserne; Tilfredshed; Underkastelse under Sædelæren, og hold Dig til gode Venner, hvis Vandel er ren og ihærdig; saadan maa en klog Tiggermunk her i Verden begynde.",
  "376": "Hans Vandel skal være venlig og pletfri, saa vil han fuld af Glæde faa Ende paa Lidelsen.",
  "377": "Som Jasminen kaster sine visne Blomster fra sig, saadan skal I, Tiggermunke, aflægge Attraa og Had.",
  "378": "Den Tiggermunk, hvis Legeme og Tale er rolig; som er rolig og har Hold paa sine Tanker, og som har udspyet Verdens Lyster, han kaldes en, der har fundet Ro.",
  "379": "Anspor Dig selv ved egen Hjælp, prøv Dig selv ved egen Hjælp; vogtende paa Dig selv og med Hold paa Din Tanke vil Du leve lykkeligt, Tiggermunk!",
  "380": "Thi Jeget er sin egen Herre, og Jeget er sin egen Tilflugt; derfor tæm Dit Jeg som Købmanden en ædel Hest.",
  "381": "Den Tiggermunk, som er fuld af Glæde, og som finder sin Lykke i Buddhas Lære, han kommer til et fredet Sted, Lykken ved at Spirerne til nyt Liv er faldet til Ro.",
  "382": "Den Tiggermunk, der skønt ung, følger Buddhas Lære, han faar som Maanen fra en skyfri Himmel denne Verden til at straale.",
  "chap26": "Brahmanen",
  "383": "Bryd Strømmen med Magt, jag Ønskerne bort, Brahman! Naar Du har erkendt, hvorledes Spirerne til nyt Liv svinder, saa kender Du det uskabte.",
  "384": "Naar en Brahman i to Ting er naaet hinsides, saa forsvinder alle Tilknytninger for den, der erkender.",
  "385": "Den for hvem der hverken eksisterer noget hinsidigt eller noget dennesidigt eller begge Dele; den som er uden Frygt og uden Tilknytning, ham kalder jeg en Brahman.",
  "386": "Den der holder sin Tanke fast og er blottet for Urenhed; den som er rolig og har gjort sin Pligt; den som er fri for onde Indflydelser og har naaet det højeste, ham kalder jeg en Brahman.",
  "387": "Om Dagen straaler Solen, om Natten skinner Maanen, en Kriger straaler i sine Vaaben, en Brahman straaler i sin Tankes Fasthed; men Buddha straaler altid i sin Glans Dag og Nat.",
  "388": "Brahman kaldes den, der har forjaget det onde; Munk den, der fører et roligt Liv; Asket kaldes den, der har fjernet alt urent fra sig.",
  "389": "Man skal ikke anfalde en Brahman, men Brahmanen maa ikke vredes paa Angriberen. Ve over den, der slaar en Brahman, men end mere Ve over den, der vredes paa sin Angriber.",
  "390": "Det er ikke liden Vinding for en Brahman at holde sin Tanke borte fra Tillokkelser; alt efter som Trangen til at skade andre svinder, falder Lidelsen til Ro.",
  "391": "Den som ikke handler ondt med Legeme, Ord eller Tanke; den som har Hold paa sig selv i disse tre Punkter, ham kalder jeg en Brahman.",
  "392": "Den af hvem man lærer den Lære, som Buddha har forkyndt, ham skal man ære i Ærbødighed, som en Brahman ærer Offerilden.",
  "393": "Man bliver ikke Brahman ved sin Haarsætning, ved sin Slægt eller ved sin Fødsel; den der ejer Sandhed og den rette Lære, han er lykkelig, han er en Brahman.",
  "394": "Hvad hjælper Dig, Taabe, Haarsætningen, hvad hjælper Dig Gedekindskoften? I Dit Indre er der Vildnis, kun Dit Ydre holder Du rent.",
  "395": "Det Menneske, som bærer støvede Pjalter; som afmagret, saa alle Aarer ses, anspænder sin Tanke alene i Skoven, ham kalder jeg en Brahman.",
  "396": "Jeg kalder ingen en Brahman efter hans Fødsel eller efter hans Moder; han hilses maaske som Brahman og han er maaske rig; den der ikke ejer noget og intet begærer, ham kalder jeg en Brahman.",
  "397": "Den der har brudt alle Forbindelser og dog ikke frygter; den som er undsluppet alle Lænker og frelst, ham kalder jeg en Brahman.",
  "398": "Den der har brudt Rem og Baand og Lænke med alt Tilbehør; den som har skudt Slaaen fra og er vaagnet, ham kalder jeg en Brahman.",
  "399": "Den der uden at have forset sig finder sig i Forsmædelse, Slag og Lænker; den hvis Styrke er hans Taalmod, hvis Hær er hans Sjælsstyrke, ham kalder jeg en Brahman.",
  "400": "Den som ikke vredes; den som overholder de hellige Pligter; den som er god og uden Attraa; den som behersker sit Jeg og for sidste Gang er iklædt et Legeme, ham kalder jeg en Brahman.",
  "401": "Den der ikke hænger fast ved sine Ønsker, saa lidt som Vandet ved Lotusbladet eller Sennepskornet ved Naalespidsen, ham kalder jeg en Brahman.",
  "402": "Den der allerede her ser Ende paa sin Lidelse og som har kastet sin Byrde og brudt alle Forbindelser, ham kalder jeg en Brahman.",
  "403": "Den hvis Visdom er dyb; den som er klog; den som kender den rette og urette Vej; den som har naaet det højeste Maal, ham kalder jeg en Brahman.",
  "404": "Den der hverken har Samkvem med Lægfolk eller Munke, og som vandrer om uden Hjem med kun faa Ønsker, ham kalder jeg en Brahman.",
  "405": "Den som hverken øver Vold overfor frygtsomme eller kraftige Væsener, og som hverken dræber eller lader dræbe, ham kalder jeg en Brahman.",
  "406": "Den der er overbærende blandt uforsonlige, mild blandt Voldsmænd, uden Begær blandt begærlige, ham kalder jeg en Brahman.",
  "407": "Den fra hvem Attraa og Had, Hovmod og Forstillelse er faldet som et Sennepskorn fra Naalespidsen, ham kalder jeg en Brahman.",
  "408": "Den der taler sande og belærende Ord uden Plumphed, saa at han ikke støder nogen, ham kalder jeg en Brahman.",
  "409": "Den der her i Verden ikke tager noget, som ikke gives ham, det være sig langt eller kort, smaat eller stort, godt eller ondt, ham kalder jeg en Brahman.",
  "410": "Den der ikke nærer Ønsker overfor denne Verden eller Verden hisset; den som ikke støtter sig til noget og ingen Tilknytninger har, ham kalder jeg en Brahman.",
  "411": "Den der ikke nærer Ønsker og som, naar han har erkendt, ikke spørger: Hvorledes? den som har naaet Udødelighedens Dyb, ham kalder jeg en Brahman.",
  "412": "Den der er kommet ud over Tilknytning til baade godt og ondt; den som er uden Bekymring, uden Synd og ren, ham kalder jeg en Brahman.",
  "413": "Den der som Maanen er pletfri, ren, klar og usløret, og som i sig har standset al Lyst, ham kalder jeg en Brahman.",
  "414": "Den der har passeret den sumpede, vanskelige Vej Tilværelsen og Forblindelsen, som er kommet igennem og har naaet den anden Side, med Tanken fast, uden Begær, uden at spørge: Hvorledes? uden at tilegne sig noget og med tilfreds Sind, ham kalder jeg en Brahman.",
  "415": "Den som her i Verden opgiver alle Ønsker og vandrer rundt uden Hjem; den som i sig har standset al Attraa, ham kalder jeg en Brahman.",
  "416": "Den som her i Verden opgiver Begæret og vandrer rundt uden Hjem; den som i sig har standset alt Begær, ham kalder jeg en Brahman.",
  "417": "Den der opgiver al Forbindelse med Mennesker og al Forbindelse med Guder; den som er uden al Forbindelse, ham kalder jeg en Brahman.",
  "418": "Den der opgiver Lyst og Ulyst; den som er kølig og uden Svig; den Helt, der har overvundet alle Verdener, ham kalder jeg en Brahman.",
  "419": "Den der kender til Bunds alle Væseners Undergang og Fremkomst; den som ikke føler sig knyttet til Verden, men vandrer lykkelig og vakt, ham kalder jeg en Brahman.",
  "420": "Den hvis Vej Guder, Aander og Mennesker ikke kender; den hos hvem de onde Indflydelser er standset, den hellige, ham kalder jeg en Brahman.",
  "421": "Den der ikke ejer noget af, hvad der ligger forud, følger efter eller er imellem; den som intet ejer og intet begærer, ham kalder jeg en Brahman.",
  "422": "Den stærke, den ædle, den tapre, den vise, den sejrrige, den intet attraaende, den udlærte, den vakte, ham kalder jeg en Brahman.",
  "423": "Den Vismand, der kender sine tidligere Tilværelser; som ser Himmel og Helvede; som har naaet den sidste af sine Fødsler og vundet den fulde Erkendelse, og som har fuldkommet alle Fuldkommenheder, ham kalder jeg en Brahman."
};
